#nullable enable // autogenerated  

using MVZ2.GameContent.Armors;
using MVZ2.GameContent.Buffs.Enemies;
using MVZ2.GameContent.Damages;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Level;
using MVZ2.Vanilla.Properties;

using MVZ2Logic.Level;

using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Callbacks;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Level;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEnemyNames.FlagbearerZombie)]
    public class FlagbearerZombie : MonkZombie
    {
        public FlagbearerZombie(string nsp, string name) : base(nsp, name)
        {
            // 监听场上怪物死亡事件  
            AddTrigger(LevelCallbacks.POST_ENTITY_DEATH, PostEntityDeathCallback, filter: EntityTypes.ENEMY);
        }

        public override void Init(Entity entity)
        {
            base.Init(entity);
            // 初始化死亡计数为0  
            SetDeathCount(entity, 0);
            // 记录基础攻击力  
            SetBaseDamage(entity, entity.GetDamage());

            entity.SetAnimationBool("HasFlag", true);

            var speedBuff = entity.GetFirstBuff<RandomEnemySpeedBuff>();
            if (speedBuff != null)
            {
                RandomEnemySpeedBuff.SetSpeed(speedBuff, 2);
            }
        }

        private void PostEntityDeathCallback(LevelCallbacks.EntityDeathParams param, CallbackResult result)
        {
            var deadEntity = param.entity;
            var deathInfo = param.deathInfo;

            // 排除某些特殊死亡情况  
            if (deathInfo.HasEffect(VanillaDamageEffects.REMOVE_ON_DEATH) ||
                deathInfo.HasEffect(VanillaDamageEffects.DROWN) ||
                deathInfo.HasEffect(VanillaDamageEffects.FALL_OFF))
                return;

            // 查找场上所有的 FlagbearerZombie  
            var flagbearers = deadEntity.Level.FindEntities(e => e.IsEntityOf(VanillaEnemyID.FlagbearerZombie) && e.ExistsAndAlive());

            foreach (var flagbearer in flagbearers)
            {
                // 增加死亡计数  
                var deathCount = GetDeathCount(flagbearer);
                if (deathCount < MAX_DEATH_COUNT)
                {
                    deathCount++;
                    SetDeathCount(flagbearer, deathCount);

                    // 根据死亡计数增加攻击力  
                    UpdateDamage(flagbearer);
                }
            }
        }

        private void UpdateDamage(Entity entity)
        {
            var deathCount = GetDeathCount(entity);
            var baseDamage = GetBaseDamage(entity);

            // 每死亡一个怪物，攻击力+20%  
            var damageMultiplier = 1f + (deathCount * 0.2f);
            var newDamage = baseDamage * damageMultiplier;

            entity.SetDamage(newDamage);
        }

        // 获取和设置死亡计数  
        public static int GetDeathCount(Entity entity) => entity.GetBehaviourField<int>(PROP_DEATH_COUNT);
        public static void SetDeathCount(Entity entity, int value) => entity.SetBehaviourField(PROP_DEATH_COUNT, value);

        // 获取和设置基础攻击力  
        public static float GetBaseDamage(Entity entity) => entity.GetBehaviourField<float>(PROP_BASE_DAMAGE);
        public static void SetBaseDamage(Entity entity, float value) => entity.SetBehaviourField(PROP_BASE_DAMAGE, value);

        // 属性定义  
        public static readonly VanillaEntityPropertyMeta<int> PROP_DEATH_COUNT = new VanillaEntityPropertyMeta<int>("DeathCount");
        public static readonly VanillaEntityPropertyMeta<float> PROP_BASE_DAMAGE = new VanillaEntityPropertyMeta<float>("BaseDamage");

        // 常量定义  
        public const int MAX_DEATH_COUNT = 10;
    }
}